export interface CheckNameEligibilityResponse {
  code: number;
  message: string;
  data: {
    nameIsValid: boolean;
    message?: string;
  };
}

export interface CreateAdditionalCardResponse {
  Cartao: string;
  Conta: string;
  pantoken?: string;
}

export interface CheckNameEligibilityPayload {
  socialName: string;
}

export interface CreateAdditionalCardPayload {
  CPF: string;
  Conta: string;
  Nome: string;
  Limite: string;
}

export type AdditionalCardCallback = (success: boolean) => void;

export interface AdditionalCardState {
  name: string;
  isLoadingName: boolean;
  isErrorName: boolean;
  errorNameMessage: string;
  birthDate: string;
  limit: string;
  isLoading: boolean;
  isError: boolean;
  errorMessage: string;
}

export interface AdditionalCardActions {
  setName: (name: string) => void;
  setLoadingName: (isLoading: boolean) => void;
  setErrorName: (error: string) => void;
  clearNameError: () => void;
  setBirthDate: (birthDate: string) => void;
  setLimit: (limit: string) => void;
  setLoading: (isLoading: boolean) => void;
  setError: (error: string) => void;
  clearError: () => void;
  reset: () => void;
}

export interface AdditionalCardServiceContract {
  validateName: (name: string, callback?: AdditionalCardCallback) => Promise<void>;
  createAdditionalCard: (callback?: AdditionalCardCallback) => Promise<void>;
}

export interface UpdateAddressResponse {
  status?: {
    codigoRetorno: number;
    mensagem?: string;
  };
  data?: unknown;
  error?: boolean;
  description?: string;
  salvarResponse?: unknown;
}

export interface AddressValidationPayload {
  PostalCode?: string;
  Street?: string;
  Number?: string;
  Neighborhood?: string;
  State?: string;
  City?: string;
  Complement?: string | null;
  Reference?: string | null;
}

export interface AddressValidationError {
  field: string;
  message: string;
}

export interface AddressValidationResponse {
  code: number;
  message: string;
  data: {
    validated: boolean;
    errors?: AddressValidationError[];
  };
}

export type AddressValidationCallback = (
  success: boolean,
  errors?: AddressValidationError[]
) => void;

