    27→  const [value, cents] = String(fullValue).replace('-', '').split('.');
    28→
    29→  const formattedCents = cents ? cents.padEnd(2, '0') : '00';
    30→  let formattedValue = '';
    31→
    32→  for (let i = 0; i < value.length; i += 1) {
    33→    const currentDigit = value[value.length - 1 - i];
    34→
    35→    if (i > 0 && i % 3 === 0) {
    36→      formattedValue = `${currentDigit}.${formattedValue}`;
    37→    } else {
