    61→    } else {
    62→      formattedValue = `${currentDigit}${formattedValue}`;
    63→    }
    64→  }
    65→
    66→  return `${formattedValue},${formattedCents.slice(0, decimalPlaces)}`;
    67→};
    68→
    69→export const formatToInternationalCurrency = (
    70→  moneyType: string,
    71→  fullValue: number | undefined | string
    72→): string => {
    73→  if (typeof fullValue === 'undefined') return `${moneyType} 0,00`;
    74→
    75→  const [value, cents] = String(fullValue).replace('-', '').split(',');
    76→
    77→  const formattedCents = cents ? cents.padEnd(2, '0') : '00';
    78→  let formattedValue = '';
