   208→
   209→export const formatCurrencyCode = (currencyCode?: string) => {
   210→  switch (currencyCode) {
   211→    case 'BRL':
   212→      return 'R$';
   213→    case 'USD':
   214→      return 'US$';
   215→    case 'EUR':
   216→      return '€';
   217→    default:
   218→      return '$';
   219→  }
   220→};
   221→
   222→export const removeCurrencyToken = (value: string) => value.replace('R$', '');
   223→
   224→export const currencyStringToFloat = (value: string) =>
   225→  parseFloat(value.replace(/\./g, '').replace(',', '.'));
   226→
   227→export const getActiveInvoice = (
   228→  invoices: InvoiceFintechItem[]
   229→): { index: number; data: InvoiceFintechItem } | undefined => {
   230→  let hasInvoiceOverdue: { index: number; data: InvoiceFintechItem } | undefined;
   231→  let hasInvoiceClosed: { index: number; data: InvoiceFintechItem } | undefined;
   232→  let hasInvoiceOpen: { index: number; data: InvoiceFintechItem } | undefined;
   233→  const copyInvoices = [...invoices];
   234→  copyInvoices.reverse().map((invoice, index) => {
   235→    const movedToNextInvoice = invoice.Pagamento === 'Não Pago' && invoice.Situacao === 'paid';
   236→
   237→    if (movedToNextInvoice) return;
   238→
   239→    if (invoice.Pagamento === 'Não Pago' && invoice.Situacao !== 'unidentifiedPayment') {
   240→      if (
   241→        !hasInvoiceOverdue &&
   242→        isInvoiceOverdue(invoice.Vencimento) &&
   243→        invoice.Situacao !== 'paid'
   244→      ) {
   245→        hasInvoiceOverdue = { index, data: invoice };
   246→      } else if (!hasInvoiceClosed && isInvoiceClosed(invoice.Fechamento, invoice.Vencimento)) {
   247→        hasInvoiceClosed = { index, data: invoice };
   248→      } else if (!hasInvoiceOpen) {
   249→        hasInvoiceOpen = { index, data: invoice };
   250→      }
   251→    }
   252→  });
   253→
   254→  if (hasInvoiceOverdue) {
   255→    return hasInvoiceOverdue;
   256→  }
   257→
   258→  if (hasInvoiceClosed) {
   259→    return hasInvoiceClosed;
   260→  }
   261→
   262→  if (hasInvoiceOpen) {
   263→    return hasInvoiceOpen;
   264→  }
   265→  const indexDefault = copyInvoices.length > 0 ? copyInvoices.length - 1 : 0;
   266→  return { index: indexDefault, data: copyInvoices[indexDefault] };
   267→};
