import { MaskService } from 'react-native-masked-text';

export const getOnlyNumber = (value: string) => value.replace(/[^\d]/g, '');

export const cepMask = (cep: string) =>
  MaskService.toMask('custom', cep, {
    mask: '99999-999',
  });

const phoneMask = (phone: string) =>
  MaskService.toMask('custom', phone, {
    mask: '(99) 9 9999-9999',
  });

export const accountMask = (value: string) => {
  const firstDigits = value.slice(0, 2);
  return firstDigits.padEnd(value.length, '*');
};

