import CryptoES from 'crypto-es';
import { NativeModules, Platform } from 'react-native';
import Reactotron from 'reactotron-react-native';
import forge from 'node-forge';
import environment from '~/settings/environment';
import { logRequest, logResponse, logError} from '@semparar/mf-app-user';

interface ApiResponse {
  status: number;
  data: any;
}

interface Params {
  [key: string]: string;
}

interface Headers {
  [key: string]: string;
}

interface Config {
  params: Params;
  headers: Headers;
  url: string;
}

type RequestInterceptor = (params: {} | Config) => Promise<void>;
type ResponseInterceptor = (response: ApiResponse) => Promise<ApiResponse>;

interface Api {
  getCurl(
    method: string,
    formattedUri: string,
    headers: Record<string, string> | undefined,
    formattedBody: object | undefined,
  ): string;
  getValidateKey(): string;
  getIsNotExceptionValidateTokenDomain(url: string): boolean;
  getIsNotExceptionRsaDomain(url: string): boolean;
  encryptRSA(hmacNodeForge: string): string;
  createHmac(payloadEncrypted: string): string;
  encryptAES(data: string, isTsIso?: boolean): string;
  getEncrypt(
    method: string,
    body: object | undefined,
  ): {
    'x-hmac-hash': string;
    'x-ts-iso': string;
  };
  calculateChecksum(partialUuid: string): string;
  generateSegment(length: number): string;
  getIsNotExceptionPayloadDomain(formattedUri: string): boolean;
  decryptData(data: string): object;
  encryptData(body?: object): string;
  baseUrl: string;
  config: Config | {};
  interceptors: {
    request: {
      handlers: RequestInterceptor[];
      use(handler: RequestInterceptor): void;
    };
    response: {
      handlers: ResponseInterceptor[];
      use(handler: ResponseInterceptor): void;
    };
  };
  fetch(
    method: string,
    params: {} | Config,
    body?: object,
  ): Promise<ApiResponse>;
  request(
    method: string,
    uri: string,
    params?: {} | Config,
    body?: object,
