import { PropsItemsTransactions } from '@semparar/design-system-app/src/atomic/fintech/TransactionsList/Models';
import { PropsIconsNameCore } from '@semparar/design-system-app/src/styles/Models/type.icon';
import moment from 'moment';

import { CustomTransactionsData } from '../atomic/organisms/CashbackCellDropdown/Models';
import { BankSPLus, RawBanks } from '../redux/ducks/dacc/automaticDebt';
import { InvoiceFintechItem } from '../redux/ducks/invoices';
import { ActivityResponseData } from '../redux/ducks/recentActivities';
import { cashbackListVariants } from '../redux/sagas/cashback/data';
import { invoiceCardData } from '../screens/InvoiceCard/data';
import { PayInvoiceParams } from '../screens/PayInvoice/Options/Models';
import { ParamsPaymentData } from '../screens/PayMethods/Backdrops/PaymentChange/Models';
import { moment as customMoment } from '../services/moment';
import theme from '../styles/theme';

type CurrencyValue = number | undefined | string;

type CashBackTransactions = PropsItemsTransactions & {
  percentage: number;
  cashback: string;
  resgate: boolean;
};

export const formatToCurrency = (fullValue: CurrencyValue): string => {
  if (typeof fullValue === 'undefined') return `R$ 0,00`;

  const [value, cents] = String(fullValue).replace('-', '').split('.');

  const formattedCents = cents ? cents.padEnd(2, '0') : '00';
  let formattedValue = '';

  for (let i = 0; i < value.length; i += 1) {
    const currentDigit = value[value.length - 1 - i];

    if (i > 0 && i % 3 === 0) {
      formattedValue = `${currentDigit}.${formattedValue}`;
    } else {
      formattedValue = `${currentDigit}${formattedValue}`;
    }
  }

  return `R$ ${Number(fullValue) >= 0 ? '' : '-'}${formattedValue},${formattedCents[0]}${
    formattedCents[1]
  }`;
};

export const formatToNumericCurrency = (fullValue: CurrencyValue, decimalPlaces = 2): string => {
  if (typeof fullValue === 'undefined' || fullValue === '0')
    return `0,${'0'.repeat(decimalPlaces)}`;

  const [value, cents] = String(fullValue).replace('-', '').split('.');

  const formattedCents = cents ? cents.padEnd(decimalPlaces, '0') : '0'.repeat(decimalPlaces);
  let formattedValue = '';

  for (let i = 0; i < value.length; i += 1) {
    const currentDigit = value[value.length - 1 - i];

    if (i > 0 && i % 3 === 0) {
      formattedValue = `${currentDigit}.${formattedValue}`;
    } else {
      formattedValue = `${currentDigit}${formattedValue}`;
    }
  }

  return `${formattedValue},${formattedCents.slice(0, decimalPlaces)}`;
};

export const formatToInternationalCurrency = (
  moneyType: string,
  fullValue: number | undefined | string
): string => {
  if (typeof fullValue === 'undefined') return `${moneyType} 0,00`;

  const [value, cents] = String(fullValue).replace('-', '').split(',');

  const formattedCents = cents ? cents.padEnd(2, '0') : '00';
  let formattedValue = '';

  for (let i = 0; i < value.length; i += 1) {
    const currentDigit = value[value.length - 1 - i];

    if (i > 0 && i % 3 === 0) {
      formattedValue = `${currentDigit} ${formattedValue}`;
    } else {
      formattedValue = `${currentDigit}${formattedValue}`;
    }
  }

  return `${moneyType} ${Number(fullValue) >= 0 ? '' : '-'}${formattedValue},${formattedCents}`;
};

export const formatToCurrencyActivities = (
  value: number | undefined,
  currencyCode = 'BRL'
): string => {
  if (typeof value === 'undefined') return `R$ 0,00`;

  const options = {
    style: 'currency',
    currency: currencyCode,
    minimumFractionDigits: 2,
    maximumFractionDigits: 3,
  };

  const formatNumber = new Intl.NumberFormat('pt-BR', options);

  return formatNumber.format(value);
};

export const getActivityDescription = (activity: ActivityResponseData): string | undefined => {
  return activity?.NumeroParcelas > 0 ? `Parcelado em ${activity?.NumeroParcelas}x` : undefined;
};

export const getActivityIconography = (
  activity: ActivityResponseData,
  customerCard: string
): {
  name: PropsIconsNameCore;
  color: string;
  titleColor?: string;
  valueColor?: string;
  descriptionColor?: string;
} => {
  const isPaymentOrCashback =
    activity?.CodigoTransacao === 8003 ||
    activity?.CodigoTransacao === 8306 ||
    activity?.CodigoTransacao === 8019 ||
    activity?.CodigoTransacao === 8356;

  if (isPaymentOrCashback) {
    const nameIcon: Record<number, PropsIconsNameCore> = {
      8003: 'icon-circle-check',
      8306: 'icon-cashback',
      8019: 'icon-circle-check',
      8356: 'icon-cashback',
    };

    return {
      name: nameIcon?.[activity?.CodigoTransacao] ?? 'icon-cashback',
      color: theme.colors.PLUS_COLOR_02,
      titleColor: theme.colors.PLUS_COLOR_02,
      valueColor: theme.colors.PLUS_COLOR_02,
      descriptionColor: theme.colors.PLUS_COLOR_02,
    };
  }

  // Estorno
  if (activity?.CodigoTransacao === 8324) {
    return {
      name: 'icon-corner-up-left',
      color: theme.colors.BRAND_COMPLEMENT_01,
    };
  }

  if (/reversao|reversão|estorno/i.test(activity?.Descricao)) {
    return {
      name: 'icon-corner-up-left',
      color: theme.colors.BRAND_COMPLEMENT_01,
    };
  }

  // Outros lançamentos (mesalidade)
  if (/mensalidade/i.test(activity?.Descricao)) {
    return {
      name: 'icon-money',
      color: theme.colors.BRAND_COMPLEMENT_01,
    };
  }

  // Compras no cartão (físico e virtual) não lançadas na fatura
  if (activity?.Tipo === 'R' && activity?.Sequencia < 0) {
    return { name: 'icon-card-check', color: theme.colors.BRAND_COMPLEMENT_01 };
  }

  const onUsPaymentType = activity?.NumeroCartao?.endsWith(customerCard?.slice(-4));

  if (onUsPaymentType) {
    // Compras na tag (pedágio, abastece, Drive-trhu, Lava-rápido)
    return {
      name: 'icon-car-front-tag',
      color: theme.colors.BRAND_COMPLEMENT_01,
    };
  }

  // Compra cartão físico já lançada na fatura
  if (/fisico/i.test(activity?.TipoCartao)) {
    return {
      name: 'icon-card',
      color: theme.colors.BRAND_COMPLEMENT_01,
    };
  }

  // Compras cartão virtual/Online já lançada na fatura
  if (/virtual/i.test(activity?.TipoCartao)) {
    return {
      name: 'icon-card-approximation',
      color: theme.colors.BRAND_COMPLEMENT_01,
    };
  }

  // Outros lançamentos (juros, taxas)
  return {
    name: 'icon-money',
    color: theme.colors.BRAND_COMPLEMENT_01,
  };
};

export const formatCurrencyCode = (currencyCode?: string) => {
  switch (currencyCode) {
    case 'BRL':
      return 'R$';
    case 'USD':
      return 'US$';
    case 'EUR':
      return '€';
    default:
      return '$';
  }
};

export const removeCurrencyToken = (value: string) => value.replace('R$', '');

export const currencyStringToFloat = (value: string) =>
  parseFloat(value.replace(/\./g, '').replace(',', '.'));

export const getActiveInvoice = (
  invoices: InvoiceFintechItem[]
): { index: number; data: InvoiceFintechItem } | undefined => {
  let hasInvoiceOverdue: { index: number; data: InvoiceFintechItem } | undefined;
  let hasInvoiceClosed: { index: number; data: InvoiceFintechItem } | undefined;
  let hasInvoiceOpen: { index: number; data: InvoiceFintechItem } | undefined;
  const copyInvoices = [...invoices];
  copyInvoices.reverse().map((invoice, index) => {
    const movedToNextInvoice = invoice.Pagamento === 'Não Pago' && invoice.Situacao === 'paid';

    if (movedToNextInvoice) return;

    if (invoice.Pagamento === 'Não Pago' && invoice.Situacao !== 'unidentifiedPayment') {
      if (
        !hasInvoiceOverdue &&
        isInvoiceOverdue(invoice.Vencimento) &&
        invoice.Situacao !== 'paid'
      ) {
        hasInvoiceOverdue = { index, data: invoice };
      } else if (!hasInvoiceClosed && isInvoiceClosed(invoice.Fechamento, invoice.Vencimento)) {
        hasInvoiceClosed = { index, data: invoice };
      } else if (!hasInvoiceOpen) {
        hasInvoiceOpen = { index, data: invoice };
      }
    }
  });

  if (hasInvoiceOverdue) {
    return hasInvoiceOverdue;
  }

  if (hasInvoiceClosed) {
    return hasInvoiceClosed;
  }

  if (hasInvoiceOpen) {
    return hasInvoiceOpen;
  }
  const indexDefault = copyInvoices.length > 0 ? copyInvoices.length - 1 : 0;
  return { index: indexDefault, data: copyInvoices[indexDefault] };
};

export const isInvoiceOverdue = (dueDate: string): boolean => {
  const currentDate = moment();
  const formattedDueDate = moment(dueDate).add(2, 'days');
  return formattedDueDate.isBefore(currentDate);
};

export const isInvoiceClosed = (dueDate: string, closingDate: string): boolean => {
  const currentDate = moment();
  if (moment().isAfter(closingDate) && moment(dueDate).add(2, 'days').isBefore(currentDate)) {
    return true;
  }
  return false;
};

export const transformInvoiceToPattern = (
  invoice: InvoiceFintechItem
): PayInvoiceParams['payment'] => {
  return {
    ...invoiceCardData()[invoice?.Situacao ?? 'default'],
    id: invoice?.Vencimento,
    dueDate: invoice?.Vencimento,
    invoiceValue: formatToCurrency(invoice.Valor),
    dueDateTextLeft: invoice?.Vencimento ? moment(invoice?.Vencimento).format('DD [de] MMMM') : '-',
    dueDateTextRight: formatToCurrency(invoice?.ValorPgtoMinimo),
    textPriceDebit: formatToCurrency(invoice?.ValorPago),
    hasInstallmentAvailable: !!invoice?.ParcelamentoDisponivel,
  };
};

export const fullDate = (date: Date) => {
  const months = [
    'janeiro',
    'fevereiro',
    'março',
    'abril',
    'maio',
    'junho',
    'julho',
    'agosto',
    'setembro',
    'outubro',
    'novembro',
    'dezembro',
  ];

  const day = date.getDate();
  const month = months[date.getMonth()];

  return `${day} de ${month}`;
};

export const capitalizeEachWord = (value: string): string => {
  if (!value || typeof value !== 'string') return value;
  return value
    .toLowerCase()
    .split(' ')
    .map((word) => word.charAt(0).toUpperCase() + word.slice(1))
    .join(' ');
};

export const formatSPlusBanks = (data: RawBanks[]) =>
  data
    .map(({ codigo, nome }) => ({
      id: Number(codigo),
      label: `${codigo} - ${nome}`,
      value: String(codigo),
      name: String(nome),
    }))
    .sort((a, b) => a.id - b.id) as BankSPLus[];

export const getDescription = (
  TipoParcelamento: string,
  CodigoPais: string
): string | undefined => {
  if (CodigoPais && CodigoPais !== 'BR') {
    return 'Internacional';
  }
  if (TipoParcelamento) {
    return TipoParcelamento;
  }
  return undefined;
};

export const removeExtraSpaces = (str: string): string => str.replace(/\s+/g, ' ').trim();

export const removeLeadingZeros = (number: string): string => {
  return number.replace(/^0+/, '');
};

export const groupTransactionsByDate = (transactions: CustomTransactionsData[]) => {
  if (!transactions || !transactions.length || !Reflect.ownKeys(transactions).length) return [];

  const rawData = transactions.reduce((acc, cashback, index) => {
    const formattedDate = customMoment(cashback.date).format('DD [de] MMMM');

    const dateIndex =
      acc && acc.length ? acc.findIndex((transaction) => transaction?.date === formattedDate) : 0;

    const { name, date, value, basePrice, percentage } = cashback;

    const transaction: CashBackTransactions = {
      ...cashbackListVariants.CREDITO,
      hour: customMoment(date).format('HH[h]mm'),
      title: name,
      percentage,
      resgate: cashback?.resgate || false,
      cashback: formatToCurrency(value),
      value: formatToCurrency(basePrice),
      id: Number(`${customMoment(date).format('DDMMYYYY')}${index}`),
