      acc[dateIndex]?.items?.push(transaction);
      return acc;
    }

    acc[index] = { date: formattedDate, items: [transaction] };

    return acc;
  }, []);

  return rawData.filter((data) => data && Reflect.ownKeys(data).length);
};

