import { PropsItemsTransactions } from '@semparar/design-system-app/src/atomic/fintech/TransactionsList/Models';
import { PropsIconsNameCore } from '@semparar/design-system-app/src/styles/Models/type.icon';
import moment from 'moment';

import { CustomTransactionsData } from '../atomic/organisms/CashbackCellDropdown/Models';
import { BankSPLus, RawBanks } from '../redux/ducks/dacc/automaticDebt';
import { InvoiceFintechItem } from '../redux/ducks/invoices';
import { ActivityResponseData } from '../redux/ducks/recentActivities';
import { cashbackListVariants } from '../redux/sagas/cashback/data';
import { invoiceCardData } from '../screens/InvoiceCard/data';
import { PayInvoiceParams } from '../screens/PayInvoice/Options/Models';
import { ParamsPaymentData } from '../screens/PayMethods/Backdrops/PaymentChange/Models';
import { moment as customMoment } from '../services/moment';
import theme from '../styles/theme';

type CurrencyValue = number | undefined | string;

type CashBackTransactions = PropsItemsTransactions & {
  percentage: number;
  cashback: string;
  resgate: boolean;
};

export const formatToCurrency = (fullValue: CurrencyValue): string => {
  if (typeof fullValue === 'undefined') return `R$ 0,00`;

  const [value, cents] = String(fullValue).replace('-', '').split('.');

  const formattedCents = cents ? cents.padEnd(2, '0') : '00';
  let formattedValue = '';

  for (let i = 0; i < value.length; i += 1) {
    const currentDigit = value[value.length - 1 - i];

    if (i > 0 && i % 3 === 0) {
      formattedValue = `${currentDigit}.${formattedValue}`;
    } else {
      formattedValue = `${currentDigit}${formattedValue}`;
    }
  }

  return `R$ ${Number(fullValue) >= 0 ? '' : '-'}${formattedValue},${formattedCents[0]}${
    formattedCents[1]
  }`;
};

export const formatToNumericCurrency = (fullValue: CurrencyValue, decimalPlaces = 2): string => {
  if (typeof fullValue === 'undefined' || fullValue === '0')
    return `0,${'0'.repeat(decimalPlaces)}`;

  const [value, cents] = String(fullValue).replace('-', '').split('.');

  const formattedCents = cents ? cents.padEnd(decimalPlaces, '0') : '0'.repeat(decimalPlaces);
  let formattedValue = '';

  for (let i = 0; i < value.length; i += 1) {
    const currentDigit = value[value.length - 1 - i];

    if (i > 0 && i % 3 === 0) {
      formattedValue = `${currentDigit}.${formattedValue}`;
    } else {
      formattedValue = `${currentDigit}${formattedValue}`;
    }
  }

  return `${formattedValue},${formattedCents.slice(0, decimalPlaces)}`;
};

export const formatToInternationalCurrency = (
  moneyType: string,
  fullValue: number | undefined | string
): string => {
  if (typeof fullValue === 'undefined') return `${moneyType} 0,00`;

  const [value, cents] = String(fullValue).replace('-', '').split(',');

  const formattedCents = cents ? cents.padEnd(2, '0') : '00';
  let formattedValue = '';

  for (let i = 0; i < value.length; i += 1) {
    const currentDigit = value[value.length - 1 - i];

    if (i > 0 && i % 3 === 0) {
      formattedValue = `${currentDigit} ${formattedValue}`;
    } else {
      formattedValue = `${currentDigit}${formattedValue}`;
    }
  }

  return `${moneyType} ${Number(fullValue) >= 0 ? '' : '-'}${formattedValue},${formattedCents}`;
};

export const formatToCurrencyActivities = (
  value: number | undefined,
  currencyCode = 'BRL'
): string => {
  if (typeof value === 'undefined') return `R$ 0,00`;

  const options = {
    style: 'currency',
    currency: currencyCode,
    minimumFractionDigits: 2,
    maximumFractionDigits: 3,
  };

  const formatNumber = new Intl.NumberFormat('pt-BR', options);

  return formatNumber.format(value);
};

export const getActivityDescription = (activity: ActivityResponseData): string | undefined => {
  return activity?.NumeroParcelas > 0 ? `Parcelado em ${activity?.NumeroParcelas}x` : undefined;
};

export const getActivityIconography = (
  activity: ActivityResponseData,
  customerCard: string
): {
  name: PropsIconsNameCore;
  color: string;
  titleColor?: string;
  valueColor?: string;
  descriptionColor?: string;
} => {
  const isPaymentOrCashback =
    activity?.CodigoTransacao === 8003 ||
    activity?.CodigoTransacao === 8306 ||
    activity?.CodigoTransacao === 8019 ||
    activity?.CodigoTransacao === 8356;

  if (isPaymentOrCashback) {
    const nameIcon: Record<number, PropsIconsNameCore> = {
      8003: 'icon-circle-check',
      8306: 'icon-cashback',
      8019: 'icon-circle-check',
      8356: 'icon-cashback',
    };

    return {
      name: nameIcon?.[activity?.CodigoTransacao] ?? 'icon-cashback',
      color: theme.colors.PLUS_COLOR_02,
      titleColor: theme.colors.PLUS_COLOR_02,
      valueColor: theme.colors.PLUS_COLOR_02,
      descriptionColor: theme.colors.PLUS_COLOR_02,
    };
  }

  // Estorno
  if (activity?.CodigoTransacao === 8324) {
    return {
      name: 'icon-corner-up-left',
      color: theme.colors.BRAND_COMPLEMENT_01,
    };
  }

  if (/reversao|reversão|estorno/i.test(activity?.Descricao)) {
    return {
      name: 'icon-corner-up-left',
      color: theme.colors.BRAND_COMPLEMENT_01,
    };
  }

  // Outros lançamentos (mesalidade)
  if (/mensalidade/i.test(activity?.Descricao)) {
    return {
      name: 'icon-money',
      color: theme.colors.BRAND_COMPLEMENT_01,
    };
  }

  // Compras no cartão (físico e virtual) não lançadas na fatura
  if (activity?.Tipo === 'R' && activity?.Sequencia < 0) {
    return { name: 'icon-card-check', color: theme.colors.BRAND_COMPLEMENT_01 };
  }

  const onUsPaymentType = activity?.NumeroCartao?.endsWith(customerCard?.slice(-4));

  if (onUsPaymentType) {
    // Compras na tag (pedágio, abastece, Drive-trhu, Lava-rápido)
    return {
      name: 'icon-car-front-tag',
      color: theme.colors.BRAND_COMPLEMENT_01,
    };
  }

  // Compra cartão físico já lançada na fatura
  if (/fisico/i.test(activity?.TipoCartao)) {
    return {
      name: 'icon-card',
      color: theme.colors.BRAND_COMPLEMENT_01,
    };
  }

  // Compras cartão virtual/Online já lançada na fatura
  if (/virtual/i.test(activity?.TipoCartao)) {
    return {
      name: 'icon-card-approximation',
      color: theme.colors.BRAND_COMPLEMENT_01,
    };
  }

  // Outros lançamentos (juros, taxas)
  return {
    name: 'icon-money',
    color: theme.colors.BRAND_COMPLEMENT_01,
  };
};

export const formatCurrencyCode = (currencyCode?: string) => {
  switch (currencyCode) {
